[['#!/usr/bin/env python3\n\nimport subprocess\nimport json\nimport sys\nimport time\n\ndef check_chrome_debug_port(port=9222):\n    """Vérifie si Chrome remote debugging est accessible sur le port."""\n    try:\n        import urllib.request\n        url = f"http://127.0.0.1:{port}/json/version"\n        with urllib.request.urlopen(url, timeout=2) as resp:\n            data = json.loads(resp.read().decode())\n            return "webSocketDebuggerUrl" in data\n    except Exception as e:\n        print(f"❌ Chrome debug port {port} not accessible: {e}")\n        return False\n\ndef ensure_chrome_running(port=9222):\n    """Assure que Chrome est démarré avec remote debugging."""\n    if check_chrome_debug_port(port):\n        print(f"✅ Chrome already running with remote debugging on port {port}")\n        return True\n    \n    print(f"⚠️ Chrome not detected on port {port}")\n    print("Please start Chrome with remote debugging enabled:")\n    print(\n        " google-chrome --remote-debugging-port=9222 \\\n          --user-data-dir=/tmp/chrome-devtools-mcp-profile"\n    )\n    print("Or enable auto-connect in Chrome: chrome://inspect/#remote-debugging")\n    return False\n\ndef test_devtools_mcp_connection():\n    """Teste que le MCP server est fonctionnel."""\n    try:\n        result = subprocess.run(\n            ["npx", "chrome-devtools-mcp@latest", "--help"],\n            capture_output=True,\n            text=True,\n            timeout=10\n        )\n        if "--browser-url" in result.stdout:\n            print("✅ chrome-devtools-mcp is installed and accessible")\n            return True\n        else:\n            print("❌ chrome-devtools-mcp doesn', 't seem to be properly installed")\n            return False\n    except Exception as e:\n        print(f"❌ Error checking chrome-devtools-mcp: {e}")\n        return False\n\ndef main():\n    print("🔍 Checking Chrome DevTools MCP environment...")\n    print()\n    \n    # Check MCP server\n    mcp_ok = test_devtools_mcp_connection()\n    print()\n    \n    # Check Chrome\n    chrome_ok = ensure_chrome_running()\n    print()\n    \n    if mcp_ok and chrome_ok:\n        print("✅ All systems go! Chrome DevTools MCP ready for Novahiz OS.")\n        print("\nNext steps:")\n        print("1. Configure OpenCode MCP in ~/.config/opencode/opencode.json")\n        print("2. Install skill chrome-devtools-mcp in Novahiz")\n        print("3. Test with: nv route "debug login" → should return ralph-browser")\n        return 0\n    else:\n        print("⚠️ Some checks failed. Please follow the instructions above.")\n        return 1\n\nif __name__ == "__main__":\n    sys.exit(main())']]